/**
 * Compares number values in columns.
 */
export declare function numberlikeCompare(valueA: number | string | bigint, valueB: number | string | bigint): number;
/**
 * Compares alphanumeric values in columns.
 */
export declare function alphanumericCompare(valueA: string, valueB: string): number;
/**
 * Compares string values in columns.
 */
export declare function stringlikeCompare(valueA: string, valueB: string): number;
/**
 * Compares case-sensitive string values in columns.
 */
export declare function stringlikeCompareCaseSensitive(valueA: string, valueB: string): number;
/**
 * Compares datetime values in columns.
 * Supported:
 * - number: milliseconds since Unix epoch
 * - string: ISO-like datetime, supports up to 9 fractional digits
 * - Date: JS Date instance
 */
export declare function datelikeCompare(valueA: number | string | Date, valueB: number | string | Date): number;
